class Main {
  public static void main(String[] args) {
    String[] backpack = {"Sword", "Shield", "Health Potion", "Map"};

    // i starts at 0, and stops before it hits backpack.length (4)
    for (int i = 0; i < backpack.length; i++) {
      System.out.println(backpack[i]);
    }
  }
}

class Main {
  public static void main(String[] args) {
    String[] backpack = {"Sword", "Shield", "Potion"};

    // Read as: "For each String 'item' in 'backpack'"
    for (String item : backpack) {
      System.out.println(item);
    }
  }
}
